/**
 * policy-migration.js — controller for dashboards/policy-migration.html
 *
 * Renders the SweetProcess → Policies Hub migration tracker from the static
 * snapshot dashboards/policy-migration-data.json (regenerated by Claude each
 * work session — this page is read-only status, not a CMS).
 *
 * Errors surface to .dash-error-banner via DashPage.showError() —
 * never silently fall back to stale data.
 */
(function () {
    'use strict';

    var DATA = null;
    var state = { q: '', tiers: {} };

    var TIER_LABEL = {
        CORE: '⭐ CORE — Claude updates & publishes',
        ERIK: '🙋 ERIK — needs Erik facts',
        AUTO: '🤖 AUTO — archive/retire pile'
    };

    document.addEventListener('DOMContentLoaded', function () {
        loadData().catch(function (err) {
            console.error('[policy-migration] load failed:', err);
            DashPage.showError('Unable to load migration data. Please refresh — or check the console.');
        });
    });

    function esc(s) {
        return String(s == null ? '' : s)
            .replace(/&/g, '&amp;').replace(/</g, '&lt;')
            .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
    }

    async function loadData() {
        // Same-origin static snapshot — plain fetch (fetch-timeout.js wraps window.fetch
        // with the 15s timeout). DashPage.fetchJson is NOT used: it prefixes the proxy
        // BASE_URL, which is wrong for this local file.
        var resp = await fetch('/dashboards/policy-migration-data.json', { cache: 'no-store' });
        if (!resp.ok) throw new Error('data fetch HTTP ' + resp.status);
        DATA = await resp.json();
        renderStats();
        renderQuestions();
        renderWaveLog();
        renderChips();
        renderTable();
    }

    function isDone(r) {
        return r.n.indexOf('PUBLISHED') === 0 || r.n.indexOf('VERIFIED') === 0 ||
               r.v === 'COVERED-HUB' || r.v === 'COVERED-TRAINING';
    }

    function renderStats() {
        var rows = DATA.rows;
        var done = rows.filter(isDone).length;
        var coreLeft = rows.filter(function (r) { return r.tier === 'CORE' && !isDone(r); }).length;
        var junk = rows.filter(function (r) { return r.v === 'RETIRE' || r.v === 'ARCHIVE'; }).length;
        document.getElementById('stat-live').textContent = DATA.stats.hub_live;
        document.getElementById('stat-done').textContent = done + ' / ' + (rows.length + DATA.confidential_count);
        document.getElementById('stat-core').textContent = coreLeft;
        document.getElementById('stat-erik').textContent = DATA.erik_questions.length;
        document.getElementById('stat-junk').textContent = junk;
    }

    function renderQuestions() {
        document.getElementById('questions-list').innerHTML = DATA.erik_questions
            .map(function (q) { return '<li>' + esc(q) + '</li>'; }).join('');
    }

    function renderWaveLog() {
        document.getElementById('wave-log').innerHTML = DATA.wave_log.map(function (w) {
            var link = w.pid
                ? ' <a href="/pages/policy-detail.html?id=' + encodeURIComponent(w.pid) + '">open →</a>'
                : '';
            return '<li><span class="pm-wave-when">' + esc(w.when) + '</span><span>' + esc(w.what) + link + '</span></li>';
        }).join('');
    }

    function renderChips() {
        var host = document.getElementById('tier-chips');
        host.innerHTML = '';
        ['CORE', 'ERIK', 'AUTO'].forEach(function (t) {
            var n = DATA.rows.filter(function (r) { return r.tier === t; }).length;
            var el = document.createElement('span');
            el.className = 'pm-chip';
            el.textContent = TIER_LABEL[t].split(' — ')[0] + ' (' + n + ')';
            el.title = TIER_LABEL[t];
            el.addEventListener('click', function () {
                state.tiers[t] = !state.tiers[t];
                el.classList.toggle('on');
                renderTable();
            });
            host.appendChild(el);
        });
        document.getElementById('pm-search').addEventListener('input', function (e) {
            state.q = e.target.value.toLowerCase();
            renderTable();
        });
    }

    function badge(r) {
        if (isDone(r)) return '<span class="pm-badge pm-badge--done">DONE</span>';
        if (r.tier === 'CORE') return '<span class="pm-badge pm-badge--core">CORE ' + esc(r.g) + '</span>';
        if (r.tier === 'ERIK') return '<span class="pm-badge pm-badge--erik">NEEDS ERIK</span>';
        return '<span class="pm-badge pm-badge--auto">' + esc(r.v) + '</span>';
    }

    function renderTable() {
        var anyTier = Object.keys(state.tiers).some(function (k) { return state.tiers[k]; });
        var rows = DATA.rows.filter(function (r) {
            if (anyTier && !state.tiers[r.tier]) return false;
            if (state.q && (r.t + ' ' + r.d + ' ' + r.n).toLowerCase().indexOf(state.q) === -1) return false;
            return true;
        });
        // CORE first, then ERIK, then the rest; done items sink within their group
        var order = { CORE: 0, ERIK: 1, AUTO: 2 };
        rows.sort(function (a, b) {
            var t = order[a.tier] - order[b.tier];
            if (t) return t;
            var d = (isDone(a) ? 1 : 0) - (isDone(b) ? 1 : 0);
            if (d) return d;
            return a.t.localeCompare(b.t);
        });

        var html = '<div class="pm-table-wrap"><table class="pm-table"><thead><tr>' +
            '<th>Status</th><th>Document</th><th>Dept</th><th>Hub policy</th><th>Note</th>' +
            '</tr></thead><tbody>';
        html += rows.map(function (r) {
            var hub = r.pid
                ? '<a href="/pages/policy-detail.html?id=' + encodeURIComponent(r.pid) + '">' + esc(r.pid) + '</a>'
                : '';
            return '<tr><td>' + badge(r) + '</td><td>' + esc(r.t) + '</td><td class="pm-note">' + esc(r.d) +
                '</td><td>' + hub + '</td><td class="pm-note">' + esc(r.n) + '</td></tr>';
        }).join('');
        html += '</tbody></table></div>';

        var root = document.getElementById('content-root');
        root.classList.remove('dash-loading');
        root.innerHTML = html;

        var header = document.querySelector('.dash-card-header .pm-count');
        if (!header) {
            header = document.createElement('span');
            header.className = 'pm-count';
            document.querySelectorAll('.dash-card-header')[2].appendChild(header);
        }
        header.textContent = rows.length + ' / ' + DATA.rows.length + ' documents';
    }
})();
